/// - `attempt`: Optional attempt number, bound as `attempt`
///
/// Uses strict mode — unknown variables produce `TemplateRenderError`.
pub fn render_prompt(_template: &str, _issue: &Issue, _attempt: Option<u32>) -> Result<String> {
    // Stub — will be implemented in T02
    Err(SymphonyError::Other("prompt_builder not yet implemented".to_string()))
