use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use std::collections::{BTreeMap, BTreeSet, HashMap, HashSet};
use std::fmt;
use std::ops::Deref;

// ── Issue (spec §4.1.1) ────────────────────────────────────────────────

/// Normalized issue record from the tracker.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Issue {
    pub id: String,
    pub identifier: String,
    pub title: String,
    #[serde(default)]
    pub description: Option<String>,
    #[serde(default)]
    pub priority: Option<i32>,
    pub state: String,
    #[serde(default)]
    pub branch_name: Option<String>,
    #[serde(default)]
    pub url: Option<String>,
    #[serde(default)]
    pub assignee_id: Option<String>,
    #[serde(default)]
    pub labels: Vec<String>,
    #[serde(default)]
    pub blocked_by: Vec<BlockerRef>,
    /// Whether this issue is routable to this worker (assignee filter).
    #[serde(default = "default_true")]
    pub assigned_to_worker: bool,
    #[serde(default)]
    pub created_at: Option<DateTime<Utc>>,
    #[serde(default)]
    pub updated_at: Option<DateTime<Utc>>,
}

fn default_true() -> bool {
    true
}

/// A blocker reference from an inverse relation.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BlockerRef {
    pub id: Option<String>,
    pub identifier: Option<String>,
    pub state: Option<String>,
}

// ── ApiKey ─────────────────────────────────────────────────────────────

/// A redacted API-key value.
///
/// `Debug` always prints `[REDACTED]` so the raw key can never leak into
/// tracing/log output, even via `{:?}` on a type that transitively contains
/// this field.  Use [`as_str`](ApiKey::as_str) or the `Deref<Target = str>`
/// impl to access the underlying value.
#[derive(Clone)]
pub struct ApiKey(String);

impl ApiKey {
    pub fn new(s: impl Into<String>) -> Self {
        ApiKey(s.into())
    }
    pub fn as_str(&self) -> &str {
        &self.0
    }
    pub fn into_string(self) -> String {
        self.0
    }
}

impl fmt::Debug for ApiKey {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.write_str("[REDACTED]")
    }
}

impl PartialEq for ApiKey {
    fn eq(&self, other: &Self) -> bool {
        self.0 == other.0
    }
}

impl Deref for ApiKey {
    type Target = str;
    fn deref(&self) -> &str {
        &self.0
    }
}

impl From<String> for ApiKey {
    fn from(s: String) -> Self {
        ApiKey(s)
    }
}

impl From<&str> for ApiKey {
    fn from(s: &str) -> Self {
        ApiKey(s.to_string())
    }
}

// ── Workflow Definition (spec §4.1.2) ──────────────────────────────────

/// Parsed WORKFLOW.md payload.
#[derive(Debug, Clone)]
pub struct WorkflowDefinition {
    /// YAML front matter as a raw map.
    pub config: serde_yaml::Value,
    /// Markdown body after front matter, trimmed.
    pub prompt_template: String,
}

// ── Service Config (spec §4.1.3 + §5.3) ───────────────────────────────

/// Top-level typed runtime config derived from WorkflowDefinition.config.
#[derive(Debug, Clone)]
pub struct ServiceConfig {
    pub tracker: TrackerConfig,
    pub polling: PollingConfig,
    pub workspace: WorkspaceConfig,
    pub worker: WorkerConfig,
    pub agent: AgentConfig,
    pub codex: CodexConfig,
    pub hooks: HooksConfig,
    pub server: ServerConfig,
}

impl Default for ServiceConfig {
    fn default() -> Self {
        Self {
            tracker: TrackerConfig::default(),
            polling: PollingConfig::default(),
            workspace: WorkspaceConfig::default(),
            worker: WorkerConfig::default(),
            agent: AgentConfig::default(),
            codex: CodexConfig::default(),
            hooks: HooksConfig::default(),
            server: ServerConfig::default(),
        }
    }
}

/// Tracker configuration (spec §5.3.1).
#[derive(Debug, Clone)]
pub struct TrackerConfig {
    pub kind: Option<String>,
    pub endpoint: String,
    /// The Linear API key.  Stored as [`ApiKey`] so it cannot accidentally
    /// appear in debug/tracing output — `{:?}` on this struct prints `[REDACTED]`.
    pub api_key: Option<ApiKey>,
    pub project_slug: Option<String>,
    pub assignee: Option<String>,
    pub active_states: Vec<String>,
    pub terminal_states: Vec<String>,
}

impl Default for TrackerConfig {
    fn default() -> Self {
        Self {
            kind: None,
            endpoint: "https://api.linear.app/graphql".to_string(),
            api_key: None,
            project_slug: None,
            assignee: None,
            active_states: vec!["Todo".to_string(), "In Progress".to_string()],
            terminal_states: vec![
                "Closed".to_string(),
                "Cancelled".to_string(),
                "Canceled".to_string(),
                "Duplicate".to_string(),
                "Done".to_string(),
            ],
        }
    }
}

/// Polling configuration (spec §5.3.2).
#[derive(Debug, Clone)]
pub struct PollingConfig {
    pub interval_ms: u64,
}

impl Default for PollingConfig {
    fn default() -> Self {
        Self {
            interval_ms: 30_000,
        }
    }
}

/// Workspace configuration (spec §5.3.3).
#[derive(Debug, Clone)]
pub struct WorkspaceConfig {
    pub root: String,
}

impl Default for WorkspaceConfig {
    fn default() -> Self {
        Self {
            root: default_workspace_root(),
        }
    }
}

fn default_workspace_root() -> String {
    let tmp = std::env::temp_dir();
    tmp.join("symphony_workspaces")
        .to_string_lossy()
        .to_string()
}

/// Worker configuration (SSH extension, spec §5.3 + Appendix A).
#[derive(Debug, Clone, Default)]
pub struct WorkerConfig {
    pub ssh_hosts: Vec<String>,
    pub max_concurrent_agents_per_host: Option<u32>,
}

/// Agent configuration (spec §5.3.5).
#[derive(Debug, Clone)]
pub struct AgentConfig {
    pub max_concurrent_agents: u32,
    pub max_turns: u32,
    pub max_retry_backoff_ms: u64,
    pub max_concurrent_agents_by_state: HashMap<String, u32>,
}

impl Default for AgentConfig {
    fn default() -> Self {
        Self {
            max_concurrent_agents: 10,
            max_turns: 20,
            max_retry_backoff_ms: 300_000,
            max_concurrent_agents_by_state: HashMap::new(),
        }
    }
}

/// Codex app-server configuration (spec §5.3.6).
#[derive(Debug, Clone)]
pub struct CodexConfig {
    /// Command and arguments used to launch the Codex app-server process.
    /// Stored as a list to enable exec-without-shell semantics (spec §5.3.6).
    /// The YAML field accepts either a string (`"codex app-server"`, split on
    /// whitespace) or an explicit list (`["codex", "app-server"]`).
    pub command: Vec<String>,
    pub approval_policy: serde_json::Value,
    pub thread_sandbox: String,
    pub turn_sandbox_policy: Option<serde_json::Value>,
    pub turn_timeout_ms: u64,
    pub read_timeout_ms: u64,
    pub stall_timeout_ms: u64,
}

impl Default for CodexConfig {
    fn default() -> Self {
        Self {
            command: vec!["codex".to_string(), "app-server".to_string()],
            approval_policy: serde_json::json!({
                "reject": {
                    "sandbox_approval": true,
                    "rules": true,
                    "mcp_elicitations": true
                }
            }),
            thread_sandbox: "workspace-write".to_string(),
            turn_sandbox_policy: None,
            turn_timeout_ms: 3_600_000,
            read_timeout_ms: 5_000,
            stall_timeout_ms: 300_000,
        }
    }
}

/// Hooks configuration (spec §5.3.4).
#[derive(Debug, Clone)]
pub struct HooksConfig {
    pub after_create: Option<String>,
    pub before_run: Option<String>,
    pub after_run: Option<String>,
    pub before_remove: Option<String>,
    pub timeout_ms: u64,
}

impl Default for HooksConfig {
    fn default() -> Self {
        Self {
            after_create: None,
            before_run: None,
            after_run: None,
            before_remove: None,
            timeout_ms: 60_000,
        }
    }
}

/// Server configuration (extension, spec §13.7).
#[derive(Debug, Clone)]
pub struct ServerConfig {
    pub port: Option<u16>,
    pub host: String,
}

impl Default for ServerConfig {
    fn default() -> Self {
        Self {
            port: None,
            host: "127.0.0.1".to_string(),
        }
    }
}

// ── Workspace (spec §4.1.4) ───────────────────────────────────────────

/// A prepared workspace directory for an issue run.
#[derive(Debug, Clone)]
pub struct Workspace {
    pub path: String,
    pub workspace_key: String,
    pub created_now: bool,
}

// ── RunAttempt (spec §4.1.5) ──────────────────────────────────────────

/// A single execution attempt for an issue.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RunAttempt {
    pub issue_id: String,
    pub issue_identifier: String,
    /// `None` for first attempt, `Some(n)` for retries.
    #[serde(default)]
    pub attempt: Option<u32>,
    pub workspace_path: String,
    pub started_at: DateTime<Utc>,
    pub status: String,
    #[serde(default)]
    pub error: Option<String>,
    #[serde(default)]
    pub worker_host: Option<String>,
}

// ── LiveSession (spec §4.1.6) ─────────────────────────────────────────

/// Tracks the active Codex session for a running issue.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LiveSession {
    pub session_id: String,
    pub thread_id: String,
    pub turn_id: String,
    #[serde(default)]
    pub codex_app_server_pid: Option<String>,
    #[serde(default)]
    pub last_codex_event: Option<String>,
    #[serde(default)]
    pub last_codex_timestamp: Option<DateTime<Utc>>,
    #[serde(default)]
    pub last_codex_message: Option<String>,
    #[serde(default)]
    pub codex_input_tokens: u64,
    #[serde(default)]
    pub codex_output_tokens: u64,
    #[serde(default)]
    pub codex_total_tokens: u64,
    #[serde(default)]
    pub last_reported_input_tokens: u64,
    #[serde(default)]
    pub last_reported_output_tokens: u64,
    #[serde(default)]
    pub last_reported_total_tokens: u64,
    #[serde(default)]
    pub turn_count: u32,
    pub started_at: DateTime<Utc>,
    #[serde(default)]
    pub worker_host: Option<String>,
}

// ── RetryEntry (spec §4.1.7) ──────────────────────────────────────────

/// An issue queued for retry after a failed attempt.
#[derive(Debug, Clone)]
pub struct RetryEntry {
    pub issue_id: String,
    pub identifier: String,
    pub attempt: u32,
    /// Monotonic millisecond timestamp when retry is due.
    pub due_at_ms: i64,
    /// Opaque handle — concrete type wired in S06.
    pub timer_handle: Option<String>,
    pub error: Option<String>,
    pub worker_host: Option<String>,
    pub workspace_path: Option<String>,
}

// ── CodexTotals ───────────────────────────────────────────────────────

/// Aggregate token and time accounting across all agent sessions.
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct CodexTotals {
    pub input_tokens: u64,
    pub output_tokens: u64,
    pub total_tokens: u64,
    pub seconds_running: f64,
}

// ── RateLimitInfo ─────────────────────────────────────────────────────

/// Opaque rate-limit snapshot captured from agent events.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RateLimitInfo {
    pub data: serde_json::Value,
}

// ── OrchestratorState (spec §4.1.8) ───────────────────────────────────

/// Mutable runtime state of the orchestrator loop.
#[derive(Debug, Clone)]
pub struct OrchestratorState {
    pub poll_interval_ms: u64,
    pub max_concurrent_agents: u32,
    pub running: HashMap<String, RunAttempt>,
    pub claimed: HashSet<String>,
    pub retry_attempts: HashMap<String, RetryEntry>,
    pub completed: HashSet<String>,
    pub codex_totals: CodexTotals,
    pub codex_rate_limits: Option<RateLimitInfo>,
}

// ── OrchestratorSnapshot (S06→S07 boundary) ───────────────────────────

/// A single retry entry in the snapshot (sorted, serializable).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RetrySnapshotEntry {
    pub issue_id: String,
    pub identifier: String,
    pub attempt: u32,
    pub due_in_ms: i64,
    pub error: Option<String>,
    pub worker_host: Option<String>,
    pub workspace_path: Option<String>,
}

/// Polling state for the snapshot.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PollingSnapshot {
    pub checking: bool,
    pub next_poll_in_ms: i64,
    pub poll_interval_ms: u64,
}

/// Read-only serializable view of orchestrator state for the HTTP API.
/// Uses `BTreeMap` for deterministic JSON key ordering.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OrchestratorSnapshot {
    pub poll_interval_ms: u64,
    pub max_concurrent_agents: u32,
    pub running: BTreeMap<String, RunAttempt>,
    pub claimed: BTreeSet<String>,
    pub retry_queue: Vec<RetrySnapshotEntry>,
    pub completed: BTreeSet<String>,
    pub codex_totals: CodexTotals,
    pub codex_rate_limits: Option<RateLimitInfo>,
    pub polling: PollingSnapshot,
}

// ── AgentEvent (spec §10.4) ───────────────────────────────────────────

/// Events emitted by a Codex agent session, parsed from the event stream.
#[derive(Debug, Clone)]
pub enum AgentEvent {
    SessionStarted {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        session_id: String,
    },
    StartupFailed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        error: String,
    },
    TurnCompleted {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        message: Option<String>,
    },
    TurnFailed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        error: String,
    },
    TurnCancelled {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
    },
    TurnEndedWithError {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        error: String,
    },
    TurnInputRequired {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        turn_id: String,
        prompt: Option<String>,
    },
    ApprovalAutoApproved {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        tool_call: String,
    },
    UnsupportedToolCall {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        tool_name: String,
    },
    Notification {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        message: String,
    },
    OtherMessage {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        raw: serde_json::Value,
    },
    Malformed {
        timestamp: DateTime<Utc>,
        codex_app_server_pid: Option<String>,
        raw_text: String,
        parse_error: String,
    },
}

//! Integration tests for path_safety, workspace, and prompt_builder modules.
//!
//! Runs against real filesystem (tempfile dirs) and real subprocess execution.

use std::fs;
use std::os::unix::fs as unix_fs;
use std::path::{Path, PathBuf};

use chrono::{DateTime, Utc};
use tempfile::TempDir;

use symphony::domain::{BlockerRef, HooksConfig, Issue, WorkspaceConfig};
use symphony::error::SymphonyError;
use symphony::path_safety;

// ═══════════════════════════════════════════════════════════════════════
// Path Safety — 6 tests
// ═══════════════════════════════════════════════════════════════════════

#[test]
fn test_sanitize_identifier_replaces_unsafe_chars() {
    assert_eq!(path_safety::sanitize_identifier("MT/Det"), "MT_Det");
    assert_eq!(path_safety::sanitize_identifier("S-1"), "S-1");
    assert_eq!(path_safety::sanitize_identifier("hello world!"), "hello_world_");
    assert_eq!(path_safety::sanitize_identifier("a/b\\c:d"), "a_b_c_d");
    // Dots and underscores are safe
    assert_eq!(path_safety::sanitize_identifier("v1.2_rc"), "v1.2_rc");
}

#[test]
fn test_sanitize_identifier_nil_or_empty() {
    assert_eq!(path_safety::sanitize_identifier(""), "issue");
    assert_eq!(path_safety::sanitize_identifier("  "), "issue");
}

#[test]
fn test_canonicalize_existing_path() {
    let tmp = TempDir::new().unwrap();
    let dir = tmp.path().join("sub").join("dir");
    fs::create_dir_all(&dir).unwrap();

    let result = path_safety::canonicalize(&dir).unwrap();
    // Must be absolute
    assert!(result.is_absolute());
    // Must resolve to the real path (same as std::fs::canonicalize for existing paths)
    let expected = fs::canonicalize(&dir).unwrap();
    assert_eq!(result, expected);
}

#[test]
fn test_canonicalize_nonexistent_tail() {
    let tmp = TempDir::new().unwrap();
    let existing = tmp.path().join("real");
    fs::create_dir_all(&existing).unwrap();

    // "real/nonexistent/deep" — real exists, nonexistent and deep do not
    let target = existing.join("nonexistent").join("deep");
    let result = path_safety::canonicalize(&target).unwrap();

    // The existing prefix should be resolved (canonicalized)
    let canonical_existing = fs::canonicalize(&existing).unwrap();
    let expected = canonical_existing.join("nonexistent").join("deep");
    assert_eq!(result, expected);
}

#[test]
fn test_canonicalize_symlink_resolution() {
    let tmp = TempDir::new().unwrap();
    let real_dir = tmp.path().join("real_target");
    fs::create_dir_all(&real_dir).unwrap();

    let link_path = tmp.path().join("link");
    unix_fs::symlink(&real_dir, &link_path).unwrap();

    let result = path_safety::canonicalize(&link_path).unwrap();
    let expected = fs::canonicalize(&real_dir).unwrap();
    assert_eq!(result, expected);
}

#[test]
fn test_canonicalize_nested_symlink() {
    let tmp = TempDir::new().unwrap();
    let real_dir = tmp.path().join("final_target");
    fs::create_dir_all(&real_dir).unwrap();

    // chain: link_a -> link_b -> final_target
    let link_b = tmp.path().join("link_b");
    unix_fs::symlink(&real_dir, &link_b).unwrap();

    let link_a = tmp.path().join("link_a");
    unix_fs::symlink(&link_b, &link_a).unwrap();

    let result = path_safety::canonicalize(&link_a).unwrap();
    let expected = fs::canonicalize(&real_dir).unwrap();
    assert_eq!(result, expected);
}

// ═══════════════════════════════════════════════════════════════════════
// Workspace Manager — 12 tests
// ═══════════════════════════════════════════════════════════════════════

// Helper to build a minimal WorkspaceConfig pointing at a temp root
fn workspace_config(root: &Path) -> WorkspaceConfig {
    WorkspaceConfig {
        root: root.to_string_lossy().to_string(),
    }
}

fn hooks_config_none() -> HooksConfig {
    HooksConfig {
        after_create: None,
        before_run: None,
        after_run: None,
        before_remove: None,
        timeout_ms: 5_000,
    }
}

#[allow(dead_code)]
fn make_test_issue(identifier: &str) -> Issue {
    Issue {
        id: "test-id-123".to_string(),
        identifier: identifier.to_string(),
        title: "Test Issue".to_string(),
        description: None,
        priority: None,
        state: "Todo".to_string(),
        branch_name: None,
        url: None,
        assignee_id: None,
        labels: vec![],
        blocked_by: vec![],
        assigned_to_worker: true,
        created_at: None,
        updated_at: None,
    }
}

#[test]
fn test_workspace_deterministic_path() {
    // Same identifier → same path; basename matches sanitized id
    let tmp = TempDir::new().unwrap();
    let root = tmp.path().join("workspaces");
    fs::create_dir_all(&root).unwrap();

    let _config = workspace_config(&root);
    let id = "MT-42";

    let sanitized = path_safety::sanitize_identifier(id);
    let canonical_root = path_safety::canonicalize(&root).unwrap();

    // Compute workspace path twice — must be identical
    let path1 = canonical_root.join(&sanitized);
    let path2 = canonical_root.join(path_safety::sanitize_identifier(id));
    assert_eq!(path1, path2);
    assert_eq!(path1.file_name().unwrap().to_str().unwrap(), "MT-42");
}

#[test]
fn test_workspace_creates_missing_directory() {
    let tmp = TempDir::new().unwrap();
    let root = tmp.path().join("workspaces");
    fs::create_dir_all(&root).unwrap();

    let config = workspace_config(&root);
    let hooks = hooks_config_none();

    let ws = symphony::workspace::ensure_workspace("MT-42", &config, &hooks).unwrap();
    assert!(ws.created_now);
    assert!(Path::new(&ws.path).is_dir());
}

#[test]
fn test_workspace_reuses_existing_directory() {
    let tmp = TempDir::new().unwrap();
    let root = tmp.path().join("workspaces");
    fs::create_dir_all(&root).unwrap();

    let config = workspace_config(&root);
    let hooks = hooks_config_none();

    // First call creates
    let ws1 = symphony::workspace::ensure_workspace("MT-42", &config, &hooks).unwrap();
    assert!(ws1.created_now);

    // Drop a marker file
    let marker = PathBuf::from(&ws1.path).join("marker.txt");
    fs::write(&marker, "exists").unwrap();

    // Second call reuses
    let ws2 = symphony::workspace::ensure_workspace("MT-42", &config, &hooks).unwrap();
    assert!(!ws2.created_now);
    assert_eq!(ws1.path, ws2.path);

    // Marker file still exists — directory was NOT recreated
    assert!(marker.exists());
}

#[test]
fn test_workspace_replaces_non_directory() {
    let tmp = TempDir::new().unwrap();
    let root = tmp.path().join("workspaces");
    fs::create_dir_all(&root).unwrap();

    let config = workspace_config(&root);
    let hooks = hooks_config_none();

    // Create a regular file where the workspace would go
    let sanitized = path_safety::sanitize_identifier("MT-42");
    let canonical_root = path_safety::canonicalize(&root).unwrap();
    let file_path = canonical_root.join(&sanitized);
    fs::write(&file_path, "I am a file").unwrap();
    assert!(file_path.is_file());

    // ensure_workspace should replace it with a directory
    let ws = symphony::workspace::ensure_workspace("MT-42", &config, &hooks).unwrap();
    assert!(ws.created_now);
    assert!(Path::new(&ws.path).is_dir());
}

#[test]
fn test_workspace_rejects_symlink_escape() {
    let tmp = TempDir::new().unwrap();
    let root = tmp.path().join("workspaces");
    fs::create_dir_all(&root).unwrap();

    let outside = tmp.path().join("outside");
    fs::create_dir_all(&outside).unwrap();

    // Create a symlink inside root that points outside
    let canonical_root = path_safety::canonicalize(&root).unwrap();
    let escape_link = canonical_root.join("escape");
    unix_fs::symlink(&outside, &escape_link).unwrap();

    let config = workspace_config(&root);
    let hooks = hooks_config_none();

    let result = symphony::workspace::ensure_workspace("escape", &config, &hooks);
    match result {
